// Script Continued Below
var MyDateTimeAjax = Class.create();
MyDateTimeAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor,
{
	//  STRY0061288
	nowDate: function () {
		var data = {};
		//get the value from the date field to initialize a glidedatetime object to compare with the current time
		var dateFromField = this.getParameter('sysparm_field');
		var gdt = new GlideDateTime();
		var gdt2 = new GlideDateTime();
		//set the glidedatetime object to the date from the field to be compared to the current time
		gdt2.setValue(dateFromField);

		//  STRY0061288 - remove the timezone and just return date of the date in the user's local time zone
		// NOTE: if we add timezpone in here, this changes to getLocalTime()
		var gdtDate = gdt.getLocalDate();
		var gdt2Date = gdt2.getLocalDate();


		var now =  gdtDate.getValue();
		var dateToBeCompared = gdt2Date.getValue();
		data.now = now;
		data.valueToCompare = dateToBeCompared;
		return JSON.stringify(data);
	},

	//  STRY0061288
	compareTwoDatesWithoutTime: function(){
		var data = {};
		//get the values from the two dates to be compared
		var dateOne = this.getParameter('sysparm_dateOne');
		var dateTwo = this.getParameter('sysparm_dateTwo');
		var dt1 = new GlideDateTime();
		var dt2 = new GlideDateTime();
		var gdt = new GlideDateTime();
		//initialize the two dates with the dates coming from the form fields
		dt1.setValue(dateOne);
		dt2.setValue(dateTwo);

		//  STRY0061288 - remove the timezone and just return date of the date in the user's local time zone
		// NOTE: if we add timezpone in here, this changes to getLocalTime()
		var dt1Date = dt1.getLocalDate();
		var dt2Date = dt2.getLocalDate();
		var gdtDate = gdt.getLocalDate();

		//get the values for the two dates and an object with the current date
		var olderDate = dt1Date.getValue();
		var newerDate = dt2Date.getValue();
		var now =  gdtDate.getValue(); // use this object to provide a current date object for comparison
		data.olderDate = olderDate;
		data.newerDate = newerDate;
		data.now = now;
		return JSON.stringify(data);
	},

	//HT - STRY0052942
	//add default days to acknowledgement type suspense date
	addDaysAcknowledgementSuspenseDate:function(){

		// STRY0102134 - pass taskin so we can look up Primary Office OU and check for override schedule
		var tdc = new TaskerDurationCalculator();
		var taskId = this.getParameter('sysparam_task_id');
		var scheduleId = '';
		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grTask.get(taskId)){
			// look for Schedule override on the Primary Office OU
			if(grTask.primary_office && 
				(grTask.primary_office + '' != '') && 
				grTask.primary_office.u_schedule_override && 
				(grTask.primary_office.u_schedule_override + '' != '')){
				scheduleId=grTask.getValue('primary_office.u_schedule_override');
			}
		}
		if(scheduleId == ''){
			// if no OU schedule, load sytem default
			scheduleId = tdc.taskerDefaultScheduleId;
		}
		var data = {};
		var gdt = new GlideDateTime();
		var systemPropDefaultSuspenseDays = gs.getProperty("x_153465_discovert.#AcknowledmentTaskerTypeDefaultSuspenseDate");

		// STRY0102134 - pass taskin so we can look up Primary Office OU and check for override schedule
		if(scheduleId){
			var today = new GlideDate();
			var dayInSchedule = tdc.calculateDateOfAddedBusinessDaysWitScheduleId(scheduleId, systemPropDefaultSuspenseDays, today);
			gdt.setValue(dayInSchedule);
		} else {
			gdt.addDaysUTC(systemPropDefaultSuspenseDays);
		}

		// STRY0078779
		//var payload =  gdt.getDate().getDisplayValue();
		var payload =  gdt.getDate().getDisplayValue() + ' ' + gdt.getUserFormattedLocalTime();

		data.days_from_today = payload;
		return JSON.stringify(data);
	},

	nowDateTime: function () {
		var data = {};
		//get the value from the date field to initialize a glidedatetime object to compare with the current time
		var dateFromField = this.getParameter('sysparm_field');
		var gdt = new GlideDateTime();
		var gdt2 = new GlideDateTime();
		//set the glidedatetime object to the date from the field to be compared to the current time
		gdt2.setValue(dateFromField);
		var now =  gdt.getValue();
		var dateToBeCompared = gdt2.getValue();
		data.now = now;
		data.valueToCompare = dateToBeCompared;
		return JSON.stringify(data);
	},

	addDays: function (){
		//HT - STRY0052942
		var numberOfDaysToAdd = this.getParameter('sysparm_days');
		var data = {};
		var gdt = new GlideDateTime();
		gdt.addDaysUTC(numberOfDaysToAdd);
		var payload =  gdt.getDate().getDisplayValue();
		data.days_from_today = payload;
		return JSON.stringify(data);
	},

	compareTwoDates: function(){
		//HT - STRY0055169 
		var data = {};
		//get the values from the two dates to be compared
		var dateOne = this.getParameter('sysparm_dateOne');
		var dateTwo = this.getParameter('sysparm_dateTwo');
		var dt1 = new GlideDateTime();
		var dt2 = new GlideDateTime();
		var gdt = new GlideDateTime();
		//initialize the two dates with the dates coming from the form fields
		dt1.setValue(dateOne);
		dt2.setValue(dateTwo);
		//get the values for the two dates and an object with the current date
		var olderDate = dt1.getValue();
		var newerDate = dt2.getValue();
		var now =  gdt.getValue(); // use this object to provide a current date object for comparison
		data.olderDate = olderDate;
		data.newerDate = newerDate;
		data.now = now;
		return JSON.stringify(data);
	}
});
